'use client'

import React, { useState, useMemo, useEffect } from 'react'
import { Badge } from '@/components/ui'
import SubsidiaryPanel from './SubsidiaryPanel'
import BarcodeSelectModal from './BarcodeSelectModal'
import { useAuth } from '@/lib/auth-context'

interface CostData {
  id: number
  category: string
  product: string
  shape: string
  size: string
  cost_excluding_vat: number
  dream_settlement: number
  admin_adjustment: number
  selling_price: number
  discount_rate: number
  multiplier: number
  sales_status: string
  reflected_date: string | null
  created_at: string
  materials?: string | null
  raw_materials?: string | null
  barcode?: string | null
}

interface SubsidiaryData {
  id: number
  main_category: string
  category: string
  item_name: string
  specification: string | null
  current_price: number
  unit: string
  applied_date: string
  previous_price: number | null
  change_rate: number
  note: string | null
  created_at: string
}

interface SelectedMaterial extends SubsidiaryData {
  quantity: number
  unitCost: number
}

interface EditableCostData extends CostData {
  isModified?: boolean
  isNew?: boolean
}

interface Props {
  initialData: CostData[]
  subsidiaryData: SubsidiaryData[]
}

export default function AdminCostManager({ initialData, subsidiaryData }: Props) {
  // 권한 체크
  const { isMaster, canEdit } = useAuth()

  const [data, setData] = useState<EditableCostData[]>(initialData)
  const [activeProduct, setActiveProduct] = useState<string>('전체')
  const [isSaving, setIsSaving] = useState(false)
  const [showNewForm, setShowNewForm] = useState(false)
  const [showSubsidiaryPanel, setShowSubsidiaryPanel] = useState(false)
  const [editingRowId, setEditingRowId] = useState<number | null>(null)
  const [showBarcodeModal, setShowBarcodeModal] = useState(false)
  const [barcodeEditingRowId, setBarcodeEditingRowId] = useState<number | null>(null)
  const [expandedBarcodeRows, setExpandedBarcodeRows] = useState<Set<number>>(new Set())
  const [skuInfo, setSkuInfo] = useState<Record<string, { sku_name: string; product_category: string; selling_price: number } | null>>({})

  // 컬럼 표시/숨김 상태
  const [showBarcode, setShowBarcode] = useState(true)
  const [showRawMaterial, setShowRawMaterial] = useState(true)
  const [showSubsidiary, setShowSubsidiary] = useState(true)

  // 각 제품의 부자재 설정 저장 (복사 기능용)
  const [materialSettings, setMaterialSettings] = useState<Record<number, SelectedMaterial[]>>({})

  // 각 제품의 원자재 설정 저장
  const [rawMaterialSettings, setRawMaterialSettings] = useState<Record<number, SelectedMaterial[]>>({})
  const [showRawMaterialPanel, setShowRawMaterialPanel] = useState(false)
  const [editingRawMaterialRowId, setEditingRawMaterialRowId] = useState<number | null>(null)

  // 페이지 로드 시 부자재 표시용 materialSettings만 로드 (원가는 DB 값 유지)
  useEffect(() => {
    initialData.forEach(item => {
      if (!item.materials) return

      try {
        const materialsData = JSON.parse(item.materials) as Array<{id: number, name: string, quantity: number}>
        const updatedMaterials: SelectedMaterial[] = []

        for (const mat of materialsData) {
          const current = subsidiaryData.find(s => s.id === mat.id)
          if (current) {
            updatedMaterials.push({
              ...current,
              quantity: mat.quantity,
              unitCost: current.current_price * mat.quantity
            })
          }
        }

        if (updatedMaterials.length > 0) {
          setMaterialSettings(prev => ({
            ...prev,
            [item.id]: updatedMaterials
          }))
        }
      } catch (e) {
        // JSON 파싱 실패 시 무시
      }
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // 페이지 로드 시 원자재 표시용 rawMaterialSettings 로드
  useEffect(() => {
    initialData.forEach(item => {
      if (!item.raw_materials) return

      try {
        const rawMaterialsData = JSON.parse(item.raw_materials) as Array<{id: number, name: string, quantity: number}>
        const updatedRawMaterials: SelectedMaterial[] = []

        for (const mat of rawMaterialsData) {
          const current = subsidiaryData.find(s => s.id === mat.id)
          if (current) {
            updatedRawMaterials.push({
              ...current,
              quantity: mat.quantity,
              unitCost: current.current_price * mat.quantity
            })
          }
        }

        if (updatedRawMaterials.length > 0) {
          setRawMaterialSettings(prev => ({
            ...prev,
            [item.id]: updatedRawMaterials
          }))
        }
      } catch (e) {
        // JSON 파싱 실패 시 무시
      }
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // 제품 목록
  const products = useMemo(() => {
    const prods = Array.from(new Set(data.map(item => item.product)))
    return ['전체', ...prods.sort()]
  }, [data])

  // 필터링된 데이터
  const filteredData = useMemo(() => {
    if (activeProduct === '전체') {
      return data
    }
    return data.filter(item => item.product === activeProduct)
  }, [data, activeProduct])

  // 변경된 항목 수
  const modifiedCount = data.filter(item => item.isModified || item.isNew).length

  // 디버깅용 로그 (필요시 활성화)
  // useEffect(() => {
  //   console.log(`📊 modifiedCount: ${modifiedCount}`)
  // }, [modifiedCount])

  // 부자재 표시용 문자열 생성
  const getMaterialsDisplay = (materials: string | null | undefined): string => {
    if (!materials) return ''

    try {
      // JSON 형식 파싱
      const materialsData = JSON.parse(materials) as Array<{id: number, name: string, quantity: number}>
      return materialsData.map(m => {
        if (m.quantity === 1) {
          return m.name
        } else if (m.quantity < 1) {
          const cartonQty = Math.round(1 / m.quantity)
          return `${m.name}(${cartonQty}개입)`
        } else {
          return `${m.name}×${m.quantity}`
        }
      }).join(', ')
    } catch (e) {
      // JSON 파싱 실패 시 원본 문자열 반환 (구버전)
      return materials
    }
  }

  // 필드 업데이트
  const updateField = (id: number, field: keyof CostData, value: any) => {
    setData(prevData =>
      prevData.map(item => {
        if (item.id === id) {
          const updated = { ...item, [field]: value, isModified: true }

          // 외주가공비 변경 시: 원가 = 원자재 + 부자재 + 새 외주가공비
          if (field === 'dream_settlement') {
            const newDreamSettlement = Number(value) || 0
            const rawMaterialsCost = rawMaterialSettings[id]?.reduce((sum, mat) => sum + mat.unitCost, 0) || 0
            const materialsCost = materialSettings[id]?.reduce((sum, mat) => sum + mat.unitCost, 0) || 0
            updated.cost_excluding_vat = Math.round(rawMaterialsCost) + Math.round(materialsCost) + newDreamSettlement
          }

          // 판매가 변경 시 자동 계산
          if (field === 'selling_price' || field === 'cost_excluding_vat' || field === 'dream_settlement') {
            const sellingPrice = field === 'selling_price' ? Number(value) : item.selling_price
            const costExVat = updated.cost_excluding_vat
            const costIncVat = Math.round(costExVat * 1.1)

            updated.multiplier = costExVat > 0 ? Number((sellingPrice / costExVat).toFixed(2)) : 0
            updated.discount_rate = sellingPrice > 0 ? Number((((sellingPrice - costIncVat) / sellingPrice) * 100).toFixed(1)) : 0
          }

          return updated
        }
        return item
      })
    )
  }

  // 부자재 선택 시 원가 자동 입력
  const handleMaterialSelect = (rowId: number, materials: SelectedMaterial[]) => {
    const materialsCost = materials.reduce((sum, mat) => sum + mat.unitCost, 0)

    // 부자재 설정 저장 (복사 기능용)
    setMaterialSettings(prev => ({
      ...prev,
      [rowId]: materials
    }))

    // ID와 수량을 JSON으로 저장 (실시간 가격 반영용)
    const materialsData = materials.map(m => ({
      id: m.id,
      name: m.item_name,
      quantity: m.quantity
    }))
    const materialsJson = JSON.stringify(materialsData)

    setData(prevData =>
      prevData.map(item => {
        if (item.id === rowId) {
          // 원자재 합계 계산
          const rawMaterialsCost = rawMaterialSettings[rowId]?.reduce((sum, mat) => sum + mat.unitCost, 0) || 0

          // 원가 = 원자재 + 부자재 + 외주가공비
          const dreamSettlement = item.dream_settlement || 0
          const totalCost = Math.round(rawMaterialsCost) + Math.round(materialsCost) + dreamSettlement

          const updated = {
            ...item,
            cost_excluding_vat: totalCost,
            materials: materialsJson, // JSON 형태로 저장
            isModified: true
          }

          // 자동 계산
          const costIncVat = Math.round(totalCost * 1.1)
          updated.multiplier = totalCost > 0 ? Number((item.selling_price / totalCost).toFixed(2)) : 0
          updated.discount_rate = item.selling_price > 0 ? Number((((item.selling_price - costIncVat) / item.selling_price) * 100).toFixed(1)) : 0

          return updated
        }
        return item
      })
    )
    setShowSubsidiaryPanel(false)
    setEditingRowId(null)
  }

  // 원자재 선택 시 원가 자동 입력
  const handleRawMaterialSelect = (rowId: number, rawMaterials: SelectedMaterial[]) => {
    const rawMaterialsCost = rawMaterials.reduce((sum, mat) => sum + mat.unitCost, 0)

    // 원자재 설정 저장
    setRawMaterialSettings(prev => ({
      ...prev,
      [rowId]: rawMaterials
    }))

    // ID와 수량을 JSON으로 저장
    const rawMaterialsData = rawMaterials.map(m => ({
      id: m.id,
      name: m.item_name,
      quantity: m.quantity
    }))
    const rawMaterialsJson = JSON.stringify(rawMaterialsData)

    setData(prevData =>
      prevData.map(item => {
        if (item.id === rowId) {
          // 부자재 합계 계산
          const materialsCost = materialSettings[rowId]?.reduce((sum, mat) => sum + mat.unitCost, 0) || 0

          // 원가 = 원자재 + 부자재 + 외주가공비
          const dreamSettlement = item.dream_settlement || 0
          const totalCost = Math.round(rawMaterialsCost) + Math.round(materialsCost) + dreamSettlement

          const updated = {
            ...item,
            cost_excluding_vat: totalCost,
            raw_materials: rawMaterialsJson,
            isModified: true
          }

          // 자동 계산
          const costIncVat = Math.round(totalCost * 1.1)
          updated.multiplier = totalCost > 0 ? Number((item.selling_price / totalCost).toFixed(2)) : 0
          updated.discount_rate = item.selling_price > 0 ? Number((((item.selling_price - costIncVat) / item.selling_price) * 100).toFixed(1)) : 0

          return updated
        }
        return item
      })
    )
    setShowRawMaterialPanel(false)
    setEditingRawMaterialRowId(null)
  }

  // 바코드 토글 (콤마 구분 다중 바코드 지원)
  const toggleBarcodeInfo = async (itemId: number, barcodeString: string) => {
    const newExpanded = new Set(expandedBarcodeRows)

    if (newExpanded.has(itemId)) {
      newExpanded.delete(itemId)
    } else {
      newExpanded.add(itemId)

      // 콤마로 분리된 바코드들 모두 조회
      const barcodes = barcodeString.split(',').map(b => b.trim()).filter(b => b)
      const missingBarcodes = barcodes.filter(b => !skuInfo[b])

      if (missingBarcodes.length > 0) {
        try {
          const { supabase } = await import('@/lib/supabase')
          const { data, error } = await supabase
            .from('product_sku')
            .select('barcode, sku_name, product_category, selling_price')
            .in('barcode', missingBarcodes)

          if (!error && data) {
            const newInfo: typeof skuInfo = {}
            data.forEach(d => {
              newInfo[d.barcode] = {
                sku_name: d.sku_name,
                product_category: d.product_category,
                selling_price: d.selling_price
              }
            })
            setSkuInfo(prev => ({ ...prev, ...newInfo }))
          }
        } catch (err) {
          console.error('SKU 조회 실패:', err)
        }
      }
    }

    setExpandedBarcodeRows(newExpanded)
  }

  // 바코드 선택 시 즉시 DB 저장 (supabase 직접 호출)
  const handleBarcodeSelect = async (barcode: string, sellingPrice: number) => {
    const targetId = barcodeEditingRowId
    if (targetId === null) return

    const targetItem = data.find(item => item.id === targetId)
    if (!targetItem) return

    const masterPrice = targetItem.selling_price || 0

    try {
      const { supabase } = await import('@/lib/supabase')

      // 1. cost_data에 바코드 저장
      const { error } = await supabase
        .from('cost_data')
        .update({ barcode })
        .eq('id', targetId)

      if (error) {
        alert(`저장 실패: ${error.message}`)
        console.error('Supabase error:', error)
        return
      }

      // 2. product_sku에 판매가 동기화 (마스터 → SKU)
      if (masterPrice > 0) {
        await supabase
          .from('product_sku')
          .update({ selling_price: masterPrice })
          .eq('barcode', barcode)
      }

      // 화면 업데이트
      setData(prevData =>
        prevData.map(item =>
          item.id === targetId
            ? { ...item, barcode }
            : item
        )
      )

      // SKU 캐시 업데이트
      setSkuInfo(prev => ({
        ...prev,
        [barcode]: prev[barcode]
          ? { ...prev[barcode]!, selling_price: masterPrice }
          : prev[barcode]
      }))
    } catch (error) {
      alert(`저장 오류: ${error instanceof Error ? error.message : '알 수 없음'}`)
    } finally {
      setShowBarcodeModal(false)
      setBarcodeEditingRowId(null)
    }
  }

  const handleBarcodeSelectMultiple = async (selections: Array<{ barcode: string; sellingPrice: number; size: string }>) => {
    const targetId = barcodeEditingRowId
    if (targetId === null || selections.length === 0) return

    const targetItem = data.find(item => item.id === targetId)
    if (!targetItem) return

    const masterPrice = targetItem.selling_price || 0
    const barcodesArray = selections.map(s => s.barcode)
    const barcodesString = barcodesArray.join(',')

    try {
      const { supabase } = await import('@/lib/supabase')

      // 1. cost_data에 바코드 저장 (콤마 구분)
      const { error } = await supabase
        .from('cost_data')
        .update({ barcode: barcodesString })
        .eq('id', targetId)

      if (error) {
        alert(`저장 실패: ${error.message}`)
        console.error('Supabase error:', error)
        return
      }

      // 2. 선택된 모든 바코드의 product_sku에 판매가 동기화
      if (masterPrice > 0) {
        await supabase
          .from('product_sku')
          .update({ selling_price: masterPrice })
          .in('barcode', barcodesArray)
      }

      // 화면 업데이트
      setData(prevData =>
        prevData.map(item =>
          item.id === targetId
            ? { ...item, barcode: barcodesString }
            : item
        )
      )

      // SKU 캐시 업데이트
      setSkuInfo(prev => {
        const updated = { ...prev }
        barcodesArray.forEach(bc => {
          if (updated[bc]) {
            updated[bc] = { ...updated[bc]!, selling_price: masterPrice }
          }
        })
        return updated
      })
    } catch (error) {
      alert(`저장 오류: ${error instanceof Error ? error.message : '알 수 없음'}`)
    } finally {
      setShowBarcodeModal(false)
      setBarcodeEditingRowId(null)
    }
  }

  // 새 제품 추가
  const addNewProduct = () => {
    const newId = Math.max(...data.map(d => d.id), 0) + 1
    const newItem: EditableCostData = {
      id: newId,
      category: '러그',
      product: '미니멀러그',
      shape: '사각',
      size: '',
      cost_excluding_vat: 0,
      dream_settlement: 0,
      admin_adjustment: 0,
      selling_price: 0,
      discount_rate: 0,
      multiplier: 0,
      sales_status: '판매중',
      reflected_date: new Date().toISOString().split('T')[0],
      created_at: new Date().toISOString(),
      isNew: true,
      isModified: true
    }
    setData([newItem, ...data])
    setShowNewForm(false)
  }

  // 엑셀 다운로드 (CSV)
  const handleExcelDownload = () => {
    // CSV 헤더
    const headers = [
      '카테고리',
      '제품명',
      '모양',
      '사이즈',
      '바코드',
      '외주가공비',
      '원가(VAT제외)',
      '원가3배수(부가세미포함)',
      '원가3배수(부가세포함)',
      '관리자조정(정가)',
      '할인율',
      '판매가',
      '배수',
      '판매상태',
      '반영일자'
    ]

    // CSV 데이터 생성
    const rows = filteredData.map(item => {
      // 할인율 계산 (관리자조정 기준)
      const adminAdj = item.admin_adjustment || 0
      const sellingPrice = item.selling_price || 0
      let discountRate = '0%'
      if (adminAdj > 0 && sellingPrice > 0) {
        const rate = ((adminAdj - sellingPrice) / adminAdj) * 100
        discountRate = `${rate.toFixed(1)}%`
      }

      const costExVat = Math.round(item.cost_excluding_vat || 0)
      const costTimes3ExVat = Math.round(costExVat * 3)
      const costTimes3IncVat = Math.round(costExVat * 3 * 1.1)

      return [
        item.category,
        item.product,
        item.shape,
        item.size,
        item.barcode || '-',
        item.dream_settlement || 0,
        costExVat,
        costTimes3ExVat,
        costTimes3IncVat,
        item.admin_adjustment || 0,
        discountRate,
        item.selling_price || 0,
        item.multiplier ? item.multiplier.toFixed(2) : '-',
        item.sales_status || '-',
        item.reflected_date || '-'
      ]
    })

    // CSV 문자열 생성
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(cell => {
        // 쉼표나 따옴표가 있으면 따옴표로 감싸기
        const str = String(cell)
        if (str.includes(',') || str.includes('"') || str.includes('\n')) {
          return `"${str.replace(/"/g, '""')}"`
        }
        return str
      }).join(','))
    ].join('\n')

    // BOM 추가 (한글 깨짐 방지)
    const bom = '\uFEFF'
    const blob = new Blob([bom + csvContent], { type: 'text/csv;charset=utf-8;' })

    // 다운로드
    const link = document.createElement('a')
    const url = URL.createObjectURL(blob)
    link.setAttribute('href', url)
    link.setAttribute('download', `원가데이터_${new Date().toISOString().split('T')[0]}.csv`)
    link.style.visibility = 'hidden'
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }

  // 일괄 저장
  const handleSaveAll = async () => {
    const modifiedItems = data.filter(item => item.isModified || item.isNew)

    if (modifiedItems.length === 0) {
      alert('변경된 항목이 없습니다')
      return
    }

    setIsSaving(true)
    try {
      // 1. 바코드 검증
      const { supabase } = await import('@/lib/supabase')
      const itemsWithBarcode = modifiedItems.filter(item => item.barcode)

      if (itemsWithBarcode.length > 0) {
        const allBarcodes: string[] = []
        const barcodeToProduct: Record<string, string> = {}

        for (const item of itemsWithBarcode) {
          const barcodes = item.barcode!.split(',').map(b => b.trim()).filter(b => b)
          for (const bc of barcodes) {
            allBarcodes.push(bc)
            barcodeToProduct[bc] = `${item.product} ${item.shape} ${item.size}`
          }
        }

        // product_sku에서 바코드 조회
        const { data: existingBarcodes, error: barcodeError } = await supabase
          .from('product_sku')
          .select('barcode')
          .in('barcode', allBarcodes)

        if (barcodeError) {
          alert(`바코드 검증 실패: ${barcodeError.message}`)
          setIsSaving(false)
          return
        }

        const existingBarcodeSet = new Set(existingBarcodes?.map(b => b.barcode) || [])
        const unmatchedBarcodes = allBarcodes.filter(bc => !existingBarcodeSet.has(bc))

        if (unmatchedBarcodes.length > 0) {
          const unmatchedList = unmatchedBarcodes.map(bc =>
            `• ${bc} (${barcodeToProduct[bc]})`
          ).join('\n')

          alert(`⚠️ 매칭되지 않은 바코드가 있습니다.\n\n다음 바코드를 product_sku 테이블에 먼저 추가해주세요:\n\n${unmatchedList}`)
          setIsSaving(false)
          return
        }
      }

      // 2. 저장 진행
      const response = await fetch('/api/admin/cost/batch-update', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ items: modifiedItems })
      })

      const result = await response.json()

      if (response.ok) {
        // 바코드가 있는 항목들은 product_sku에도 판매가 동기화
        for (const item of itemsWithBarcode) {
          if (item.selling_price && item.selling_price > 0) {
            const barcodes = item.barcode!.split(',').map(b => b.trim()).filter(b => b)
            if (barcodes.length > 0) {
              await supabase
                .from('product_sku')
                .update({ selling_price: item.selling_price })
                .in('barcode', barcodes)
            }
          }
        }

        alert('저장 완료')
        window.location.reload()
      } else {
        alert(`저장 실패: ${result.error}`)
      }
