      return
    }

    try {
      const response = await fetch('/api/sync-b2b-pricing', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ product, shape, size })
      })

      const result = await response.json()

      if (response.ok) {
        if (result.results.length > 0) {
          const summary = result.results.map((r: any) =>
            `${r.b2b_size} (${r.qty}):\n` +
            `  원가: ₩${r.old_cost.toLocaleString()} → ₩${r.new_cost.toLocaleString()}\n` +
            `  마진: ₩${r.margin.toLocaleString()} (배수: ${r.multiplier}x)`
          ).join('\n\n')
          alert(`✅ B2B 원가 업데이트 완료!\n\n${summary}`)
        } else {
          alert('연동된 B2B 사이즈가 없습니다.\n\ncost_b2b_mapping 테이블에서 매핑을 추가하세요.')
