const { createClient } = require('@supabase/supabase-js');

const supabase = createClient(
  'https://ebktoazswvtqsjrjryqk.supabase.co',
  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVia3RvYXpzd3Z0cXNqcmpyeXFrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM5MDM2NzIsImV4cCI6MjA4OTQ3OTY3Mn0.a3kFa8JOBlvZ-PSMWEcIDQKLLPDrXbPf4qTRptWvki8'
);

(async () => {
  // cost_data에서 시어서커 데이터 조회
  const { data: costData, error: costError } = await supabase
    .from('cost_data')
    .select('*')
    .eq('product', '시어서커')
    .order('size', { ascending: true });

  if (costError) {
    console.log('ERROR:', costError);
    return;
  }

  console.log('╔═══════════════════════════════════════════════════════════════════════════════╗');
  console.log('║                         현재 시어서커 원가 데이터                              ║');
  console.log('╚═══════════════════════════════════════════════════════════════════════════════╝\n');
  console.log(`총 ${costData.length}개 제품\n`);

  // 테이블 형식으로 출력
  console.log('형태    사이즈       외주가공비   원가      판매가    마진율    상태');
  console.log('─'.repeat(85));

  let totalMargin = 0;
  let totalCost = 0;
  let totalPrice = 0;
  let count = 0;

  costData.forEach(item => {
    const shape = item.shape || '-';
    const size = (item.size || '-').toString().padEnd(10);
    const settlement = (item.dream_settlement || 0).toLocaleString().padStart(8);
    const cost = (item.cost_excluding_vat || 0).toLocaleString().padStart(8);
    const price = (item.selling_price || 0).toLocaleString().padStart(8);
    const margin = item.selling_price > 0 
      ? ((item.selling_price - item.cost_excluding_vat) / item.selling_price * 100).toFixed(1)
      : 0;
    const status = item.sales_status || '-';

    console.log(`${shape.padEnd(6)} ${size} ${settlement}원 ${cost}원 ${price}원 ${margin.toString().padStart(5)}%  ${status}`);

    if (item.selling_price > 0) {
      totalMargin += parseFloat(margin);
      totalCost += item.cost_excluding_vat || 0;
      totalPrice += item.selling_price || 0;
      count++;
    }
  });

  console.log('\n' + '═'.repeat(85));
  console.log('요약 통계');
  console.log('─'.repeat(85));
  console.log(`평균 외주가공비: ${(costData.reduce((s, i) => s + (i.dream_settlement || 0), 0) / costData.length).toLocaleString()}원`);
  console.log(`평균 원가:       ${(totalCost / count).toLocaleString()}원`);
  console.log(`평균 판매가:     ${(totalPrice / count).toLocaleString()}원`);
  console.log(`평균 마진율:     ${(totalMargin / count).toFixed(2)}%`);

  console.log('\n=== JSON 형식 데이터 ===');
  const simplifiedData = costData.map(item => ({
    shape: item.shape,
    size: item.size,
    외주가공비: item.dream_settlement,
    원가: item.cost_excluding_vat,
    판매가: item.selling_price,
    마진율: item.selling_price > 0 ? ((item.selling_price - item.cost_excluding_vat) / item.selling_price * 100).toFixed(2) : 0,
    상태: item.sales_status
  }));
  console.log(JSON.stringify(simplifiedData, null, 2));
})();

