'use client'

import { useState, useMemo } from 'react'
import ExcelDownloadButton from '@/components/ExcelDownloadButton'
import EditableSetsTable from '@/components/EditableSetsTable'
import SetMatchingPanel from '@/components/SetMatchingPanel'
import { Badge } from '@/components/ui'

interface SetPriceData {
  id: number
  category: string
  product: string
  set_type: string
  set_price: number
  individual_sum: number
  discount_amount: number
  discount_rate: number
  original_price: number | null
  cost_price: number | null
  multiplier: number | null
  set_details: string | null
  reflected_date: string | null
  created_at: string
}

interface SkuSet {
  barcode: string
  sku_name: string
  product_category: string
  selling_price: number | null
}

interface Props {
  initialData: SetPriceData[]
  skuSets?: SkuSet[]
}

export default function SetsDataClient({ initialData, skuSets = [] }: Props) {
  const [activeProduct, setActiveProduct] = useState<string>('전체')
  const [editingId, setEditingId] = useState<number | null>(null)

  // 제품 목록 추출
  const products = useMemo(() => {
    const prods = Array.from(new Set(initialData.map(item => item.product)))
    return ['전체', ...prods]
  }, [initialData])

  // 필터링된 데이터
  const filteredData = useMemo(() => {
    if (activeProduct === '전체') {
      return initialData
    }
    return initialData.filter(item => item.product === activeProduct)
  }, [initialData, activeProduct])

  // 4단계 그룹화: category > product > setBase > items
  const groupedData = useMemo(() => {
    return filteredData.reduce((acc, item) => {
      // "사각세트 A" -> "사각세트"로 그룹화
      const parts = item.set_type.split(' ')
      const setBase = parts.length > 1 ? parts.slice(0, -1).join(' ') : item.set_type

      if (!acc[item.category]) {
        acc[item.category] = {}
      }
      if (!acc[item.category][item.product]) {
        acc[item.category][item.product] = {}
      }
      if (!acc[item.category][item.product][setBase]) {
        acc[item.category][item.product][setBase] = []
      }
      acc[item.category][item.product][setBase].push(item)
      return acc
    }, {} as Record<string, Record<string, Record<string, SetPriceData[]>>>)
  }, [filteredData])

  // 엑셀 다운로드용 데이터
  const excelData = useMemo(() => {
    return filteredData.map(item => ({
      '카테고리': item.category,
      '제품명': item.product,
      '세트 구성': item.set_type,
      '상세 구성': item.set_details || '-',
      '정가': item.original_price || '-',
      '판매가': item.individual_sum,
      '정가 할인율': item.original_price ? `${(((item.original_price - item.individual_sum) / item.original_price) * 100).toFixed(1)}%` : '-',
      '세트 가격': item.set_price,
      '할인액': item.discount_amount,
      '세트 할인율': `${(item.discount_rate * 100).toFixed(1)}%`
    }))
  }, [filteredData])

