import { supabase } from '@/lib/supabase'
import { NextRequest, NextResponse } from 'next/server'
import { parseSetDetails, getItemInfo } from '@/lib/item-mapping'

export async function POST(request: NextRequest) {
  try {
    const { setDetails } = await request.json()

    if (!setDetails || typeof setDetails !== 'string') {
      return NextResponse.json({ error: 'Invalid setDetails' }, { status: 400 })
    }

    // 구성 품목 파싱
    const items = parseSetDetails(setDetails)

    // 각 품목의 원가 조회
    const itemCosts: Array<{
      itemName: string
      cost: number | null
      found: boolean
    }> = []

    for (const itemName of items) {
      const itemInfo = getItemInfo(itemName)

      if (!itemInfo) {
        itemCosts.push({
          itemName,
          cost: null,
          found: false
        })
        continue
      }

      // Supabase에서 원가 조회
      const { data, error } = await supabase
        .from('cost_data')
        .select('cost_excluding_vat')
        .eq('product', itemInfo.product)
        .eq('shape', itemInfo.shape)
        .eq('size', itemInfo.size)
        .single()

      if (error || !data) {
        itemCosts.push({
          itemName,
          cost: null,
          found: false
        })
      } else {
        itemCosts.push({
          itemName,
          cost: data.cost_excluding_vat,
          found: true
        })
      }
    }

    // 총 원가 계산 (부가세 포함)
    const totalCostExVat = itemCosts
      .filter(item => item.cost !== null)
      .reduce((sum, item) => sum + (item.cost || 0), 0)

    const totalCostIncVat = Math.round(totalCostExVat * 1.1)

    return NextResponse.json({
      items: itemCosts,
      totalCostExVat,
      totalCostIncVat,
      allItemsFound: itemCosts.every(item => item.found)
    })
  } catch (error) {
    console.error('Calculate error:', error)
    return NextResponse.json({ error: String(error) }, { status: 500 })
  }
}

